from __future__ import annotations
import os
from fastapi         import APIRouter, Depends, HTTPException, Request
from fastapi.responses import HTMLResponse
from pydantic        import BaseModel
from sqlalchemy.orm  import Session
from sqlalchemy      import text

from database        import get_db, License
from strategy_presets import get_all_presets, get_preset, preset_to_heartbeat_profile

router = APIRouter(prefix="/strategy", tags=["strategy"])


class SelectStrategyRequest(BaseModel):
    license_key: str
    strategy_id: str


class SelectStrategyResponse(BaseModel):
    ok:           bool
    strategy_id:  str
    profile_name: str
    message:      str


@router.get("/presets")
def list_presets():
    return {
        "presets": [
            {
                "strategy_id":     p["strategy_id"],
                "profile_name":    p["profile_name"],
                "description":     p["description"],
                "color":           p["color"],
                "symbols_hint":    p["symbols_hint"],
                "entry_type":      p["entry_type"],
                "min_score_entry": p["min_score_entry"],
                "rr_ratio":        p["rr_ratio"],
                "risk_mode":       p["risk_mode"],
                "session_filter":  p["session_filter"],
                "trailing_sl":     p["trailing_sl"],
            }
            for p in get_all_presets()
        ]
    }


@router.get("/active")
def get_active_strategy(license_key: str, db: Session = Depends(get_db)):
    lic = db.query(License).filter(License.license_key == license_key).first()
    if not lic:
        raise HTTPException(status_code=404, detail="License not found")
    sid    = getattr(lic, "strategy_id", None) or "S1"
    preset = get_preset(sid) or get_preset("S1")
    return {
        "license_key":     license_key,
        "strategy_id":     sid,
        "profile_name":    preset["profile_name"],
        "description":     preset["description"],
        "color":           preset["color"],
        "entry_type":      preset["entry_type"],
        "min_score_entry": preset["min_score_entry"],
        "rr_ratio":        preset["rr_ratio"],
        "risk_mode":       preset["risk_mode"],
    }


@router.post("/select", response_model=SelectStrategyResponse)
def select_strategy(req: SelectStrategyRequest, db: Session = Depends(get_db)):
    preset = get_preset(req.strategy_id)
    if not preset:
        raise HTTPException(status_code=400,
            detail=f"strategy_id '{req.strategy_id}' không hợp lệ. Chọn: S1, S2, S3")

    lic = db.query(License).filter(License.license_key == req.license_key).first()
    if not lic:
        raise HTTPException(status_code=404, detail="License not found")
    if lic.status not in ("ACTIVE", "UNUSED"):
        raise HTTPException(status_code=403, detail="License không active")

    old_sid         = getattr(lic, "strategy_id", None) or "S1"
    lic.strategy_id = req.strategy_id
    db.commit()

    try:
        db.execute(
            text("""INSERT INTO strategy_selection_log
                    (license_key, buyer_email, old_strategy_id, new_strategy_id, source)
                    VALUES (:key, :email, :old, :new, 'dashboard')"""),
            {"key": req.license_key, "email": getattr(lic, "buyer_email", "") or "",
             "old": old_sid, "new": req.strategy_id}
        )
        db.commit()
    except Exception:
        pass

    return SelectStrategyResponse(
        ok=True,
        strategy_id=req.strategy_id,
        profile_name=preset["profile_name"],
        message=f"Đã chuyển sang '{preset['profile_name']}'. EA cập nhật trong heartbeat kế tiếp (≤30s)."
    )


@router.get("/admin/stats")
def strategy_stats(admin_token: str, db: Session = Depends(get_db)):
    if admin_token != os.environ.get("ADMIN_SECRET_KEY", ""):
        raise HTTPException(status_code=403, detail="Unauthorized")

    rows = db.execute(
        text("""SELECT COALESCE(strategy_id,'S1') as sid, COUNT(*) as cnt
               FROM license_keys WHERE status = 'ACTIVE'
               GROUP BY sid ORDER BY cnt DESC""")
    ).fetchall()

    total    = sum(r[1] for r in rows) or 1
    presets  = {p["strategy_id"]: p for p in get_all_presets()}
    known    = set()
    breakdown = []
    for sid, cnt in rows:
        p = presets.get(sid, {})
        breakdown.append({"strategy_id": sid, "profile_name": p.get("profile_name", sid),
                          "count": cnt, "pct": round(cnt / total * 100, 1)})
        known.add(sid)
    for sid, p in presets.items():
        if sid not in known:
            breakdown.append({"strategy_id": sid, "profile_name": p["profile_name"],
                               "count": 0, "pct": 0.0})
    return {"total_active": total, "breakdown": breakdown}

