# GET /strategy/detail — Serve Strategy Detail HTML (visual edition)
# HTML includes: signal flow, entry zone chart, radar, timeline
# ══════════════════════════════════════════════════════════════════
import base64 as _b64

_DETAIL_HTML = _b64.b64decode(
    ""
).decode("utf-8")

@router.get("/detail", response_class=HTMLResponse)
async def strategy_detail_page(request: Request):
    """
    Serve Strategy Detail page với đầy đủ visual model.
    URL: /strategy/detail?tf=H1&symbols=XAUUSDm&license=xxx
    """
    return HTMLResponse(content=_DETAIL_HTML)